import { useState } from 'react';
export function GroupedList<I extends { id: string }>({ groups, renderItem }: { groups: ReadonlyArray<{ id: string; name: string; items: ReadonlyArray<I> }>; renderItem: (i: I) => React.ReactNode }) {
  const [collapsed, setCollapsed] = useState<Set<string>>(new Set());
  return (
    <div>{groups.map(g => { const isOpen = !collapsed.has(g.id); return (
      <div key={g.id}>
        <button type="button" onClick={() => setCollapsed(c => { const n = new Set(c); if (n.has(g.id)) n.delete(g.id); else n.add(g.id); return n; })} className="sticky top-0 z-10 flex items-center w-full h-8 px-3 bg-[oklch(0.97_0.005_250)] text-[12px] font-medium text-left">
          <span className="mr-2 text-[oklch(0.55_0.005_250)]">{isOpen ? '\u25BE' : '\u25B8'}</span>{g.name}<span className="ml-2 text-[11px] tabular-nums text-[oklch(0.55_0.005_250)]">{g.items.length}</span>
        </button>
        {isOpen && <ul>{g.items.map(i => <li key={i.id} className="h-9 px-3 border-b border-[oklch(0.95_0.005_250)]">{renderItem(i)}</li>)}</ul>}
      </div>
    ); })}</div>
