import { useEffect, useRef } from 'react';
export function NotificationBadge({ count }: { count: number }) {
  const prevCount = useRef(count);
  const ref = useRef<HTMLSpanElement | null>(null);
  useEffect(() => {
    if (count > prevCount.current && ref.current) { ref.current.style.transform = 'scale(1.2)'; window.setTimeout(() => { if (ref.current) ref.current.style.transform = 'scale(1)'; }, 200); }
    prevCount.current = count;
  }, [count]);
  if (count <= 0) return null;
  const label = count > 99 ? '99+' : count > 9 ? '9+' : String(count);
  return <span ref={ref} aria-label={`${count} unread`} className="inline-flex items-center justify-center min-w-[18px] h-[18px] px-1 bg-[oklch(0.6_0.18_25)] text-white text-[10px] font-medium rounded-full" style={{ transition: 'transform 200ms cubic-bezier(0.22, 1, 0.36, 1)' }}>{label}</span>;
}

// HistogramWithOutliers.tsx
export function HistogramWithOutliers({ values, binCount = 20 }: { values: ReadonlyArray<number>; binCount?: number }) {
  const sorted = [...values].sort((a, b) => a - b);
  const q = (p: number) => sorted[Math.floor((sorted.length - 1) * p)];
  const q1 = q(0.25), q3 = q(0.75); const iqr = q3 - q1;
  const lowFence = q1 - 1.5 * iqr, highFence = q3 + 1.5 * iqr;
  const min = Math.min(...values), max = Math.max(...values);
  const binSize = (max - min) / binCount;
  const bins = Array.from({ length: binCount }).map((_, i) => sorted.filter(v => v >= min + i * binSize && v < min + (i + 1) * binSize && v >= lowFence && v <= highFence).length);
  const maxBin = Math.max(...bins, 1);
  const outliers = sorted.filter(v => v < lowFence || v > highFence);
  const W = 480, H = 200;
  return (
    <svg width={W} height={H}>
      {bins.map((cnt, i) => { const h = (cnt / maxBin) * (H - 30); return <rect key={i} x={i * (W / binCount) + 1} y={H - 30 - h} width={(W / binCount) - 2} height={h} fill="oklch(0.55 0.18 250)" />; })}
      {outliers.map((v, i) => <circle key={i} cx={((v - min) / (max - min)) * W} cy={H - 15} r={3} fill="oklch(0.6 0.18 25)" />)}
    </svg>
  );
}

