const DOMAIN_TYPOS: Record<string, string> = { 'gmial.com': 'gmail.com', 'gmai.com': 'gmail.com', 'yaho.com': 'yahoo.com', 'hotmial.com': 'hotmail.com', 'outlok.com': 'outlook.com' };
export function suggestEmail(email: string): string | null {
  const at = email.indexOf('@'); if (at < 0) return null;
  const domain = email.slice(at + 1).toLowerCase();
  if (DOMAIN_TYPOS[domain]) return email.slice(0, at + 1) + DOMAIN_TYPOS[domain];
  return null;
}
