// useVimSearch.ts
import { useState, useEffect } from 'react';
export function useVimSearch() {
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState('');
  const [currentMatch, setCurrentMatch] = useState(0);
  const [matches, setMatches] = useState<HTMLElement[]>([]);
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement) return;
      if (e.key === '/' && !open) { e.preventDefault(); setOpen(true); }
      else if (e.key === 'Escape' && open) { setOpen(false); setQuery(''); }
      else if (e.key === 'n' && open) { setCurrentMatch(c => (c + 1) % Math.max(1, matches.length)); }
      else if (e.key === 'N' && open) { setCurrentMatch(c => (c - 1 + matches.length) % Math.max(1, matches.length)); }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [open, matches.length]);
  useEffect(() => { if (matches[currentMatch]) matches[currentMatch].scrollIntoView({ block: 'center' }); }, [currentMatch, matches]);
  return { open, query, setQuery, currentMatch, matches, setMatches, close: () => { setOpen(false); setQuery(''); } };
}

// MentionInput.tsx
import { useState, useMemo, useRef } from 'react';
export function MentionInput({ value, onChange, members }: { value: string; onChange: (v: string) => void; members: ReadonlyArray<{ id: string; name: string }> }) {
  const textareaRef = useRef<HTMLTextAreaElement | null>(null);
  const [mentionQuery, setMentionQuery] = useState<string | null>(null);
  const [focusIdx, setFocusIdx] = useState(0);
  const filtered = useMemo(() => mentionQuery !== null ? members.filter(m => m.name.toLowerCase().startsWith(mentionQuery.toLowerCase())).slice(0, 6) : [], [members, mentionQuery]);
  const onChangeText = (v: string) => {
    onChange(v);
    const cursor = textareaRef.current?.selectionStart ?? 0;
    const before = v.slice(0, cursor);
    const at = before.lastIndexOf('@');
    if (at >= 0 && !/\s/.test(before.slice(at + 1))) setMentionQuery(before.slice(at + 1));
    else setMentionQuery(null);
  };
  const insertMention = (member: { id: string; name: string }) => {
    const cursor = textareaRef.current?.selectionStart ?? 0;
    const at = value.slice(0, cursor).lastIndexOf('@');
    const newValue = value.slice(0, at) + `@${member.name} ` + value.slice(cursor);
    onChange(newValue);
    setMentionQuery(null);
  };
  return (
    <div className="relative">
      <textarea ref={textareaRef} value={value} onChange={(e) => onChangeText(e.target.value)} onKeyDown={(e) => { if (filtered.length > 0) { if (e.key === 'ArrowDown') { e.preventDefault(); setFocusIdx(i => Math.min(filtered.length - 1, i + 1)); } else if (e.key === 'ArrowUp') { e.preventDefault(); setFocusIdx(i => Math.max(0, i - 1)); } else if (e.key === 'Enter' || e.key === 'Tab') { e.preventDefault(); insertMention(filtered[focusIdx]); } } }} className="w-full min-h-20 p-3 text-[14px] border border-[oklch(0.85_0.005_250)] rounded outline-none focus:border-[oklch(0.55_0.18_250)] resize-y" />
      {filtered.length > 0 && (
        <ul className="absolute bottom-full mb-1 left-3 w-60 bg-[oklch(0.18_0.005_250)] text-white rounded shadow-lg">
          {filtered.map((m, i) => <li key={m.id} className={`px-3 py-1.5 text-[13px] cursor-pointer ${i === focusIdx ? 'bg-[oklch(0.28_0.005_250)]' : ''}`} onClick={() => insertMention(m)}>{m.name}</li>)}
        </ul>
      )}
    </div>
  );
}

