import { useState, useEffect, useRef } from 'react';
export function DoubleTapConfirmButton({ label, confirmLabel, onConfirm }: { label: string; confirmLabel: string; onConfirm: () => void }) {
  const [armed, setArmed] = useState(false);
  const timerRef = useRef<number | null>(null);
  useEffect(() => () => { if (timerRef.current) window.clearTimeout(timerRef.current); }, []);
  const onClick = () => {
    if (armed) { onConfirm(); setArmed(false); return; }
    setArmed(true);
    if (timerRef.current) window.clearTimeout(timerRef.current);
    timerRef.current = window.setTimeout(() => setArmed(false), 3000);
  };
  return (
    <button type="button" onClick={onClick} className="h-10 px-4 text-white text-[14px] font-medium rounded transition-colors duration-[150ms]" style={{ background: armed ? 'oklch(0.6 0.18 25)' : 'oklch(0.55 0.005 250)' }}>
      {armed ? confirmLabel : label}
    </button>
  );
}

// Streamgraph.tsx (simplified)
export interface StreamSeries { id: string; label: string; color: string; values: ReadonlyArray<number>; }
export function Streamgraph({ series, width = 600, height = 240 }: { series: ReadonlyArray<StreamSeries>; width?: number; height?: number }) {
  const N = series[0]?.values.length ?? 0;
  const totals = Array.from({ length: N }).map((_, i) => series.reduce((s, sr) => s + sr.values[i], 0));
  const maxTotal = Math.max(...totals, 1);
  const xScale = (i: number) => (i / (N - 1)) * width;
  const yScale = (v: number) => (v / maxTotal) * height;
  // For each timepoint, compute offset for each series (centered)
  return (
    <svg width={width} height={height}>
      {series.map((s, si) => {
        const path: string[] = [];
        for (let i = 0; i < N; i++) {
          let belowSum = 0; for (let j = 0; j < si; j++) belowSum += series[j].values[i];
          const myVal = s.values[i];
          const total = totals[i];
          const baseline = (height - yScale(total)) / 2;
          const top = baseline + yScale(belowSum);
          const bot = top + yScale(myVal);
          path.push(i === 0 ? `M${xScale(i).toFixed(1)} ${top.toFixed(1)}` : `L${xScale(i).toFixed(1)} ${top.toFixed(1)}`);
        }
        for (let i = N - 1; i >= 0; i--) {
          let belowSum = 0; for (let j = 0; j <= si; j++) belowSum += series[j].values[i];
          const total = totals[i];
          const baseline = (height - yScale(total)) / 2;
          const bot = baseline + yScale(belowSum);
          path.push(`L${xScale(i).toFixed(1)} ${bot.toFixed(1)}`);
        }
        path.push('Z');
        return <path key={s.id} d={path.join(' ')} fill={s.color} />;
      })}
    </svg>
  );
}

