import { useState, useEffect } from 'react';
const KEY = 'tip-dismissed-v1';
export interface Tip { id: string; condition: () => boolean; title: string; body: string; actionLabel?: string; onAction?: () => void; }
export function ContextualHelp({ tips }: { tips: ReadonlyArray<Tip> }) {
  const [dismissed, setDismissed] = useState<Set<string>>(() => { try { return new Set(JSON.parse(localStorage.getItem(KEY) ?? '[]')); } catch { return new Set(); } });
  const activeTip = tips.find(t => t.condition() && !dismissed.has(t.id));
  if (!activeTip) return null;
  const onDismiss = () => { const next = new Set(dismissed).add(activeTip.id); setDismissed(next); try { localStorage.setItem(KEY, JSON.stringify(Array.from(next))); } catch {} };
  return (
    <div role="complementary" className="fixed bottom-4 right-4 w-80 bg-[oklch(0.97_0.005_250)] border border-[oklch(0.92_0.005_250)] rounded-lg p-4 shadow" style={{ animation: 'helpIn 200ms ease-out' }}>
      <button type="button" onClick={onDismiss} aria-label="Dismiss tip" className="absolute top-2 right-2 text-[14px] text-[oklch(0.55_0.005_250)]">\u00D7</button>
      <div className="text-[13px] font-medium mb-1">{activeTip.title}</div>
      <p className="text-[12px] text-[oklch(0.45_0.005_250)]">{activeTip.body}</p>
      {activeTip.actionLabel && <button type="button" onClick={activeTip.onAction} className="mt-2 text-[12px] text-[oklch(0.55_0.18_250)] underline">{activeTip.actionLabel}</button>}
      <style>{`@keyframes helpIn { from { opacity: 0; transform: translateY(4px) } to { opacity: 1; transform: translateY(0) } } @media (prefers-reduced-motion: reduce) { [style*='helpIn'] { animation: none !important } }`}</style>
    </div>
  );
}

