import { useFrame, useThree } from '@react-three/fiber';
import { Vector3 } from 'three';
import { useRef } from 'react';
export interface CameraAnchor { position: [number, number, number]; target: [number, number, number]; }
export function AnchoredCamera({ anchors, currentIdx }: { anchors: ReadonlyArray<CameraAnchor>; currentIdx: number }) {
  const { camera } = useThree();
  const targetPos = useRef(new Vector3(...anchors[currentIdx].position));
  const targetLook = useRef(new Vector3(...anchors[currentIdx].target));
  // update targets when currentIdx changes
  useFrame(() => {
    const desired = anchors[currentIdx];
    targetPos.current.set(...desired.position);
    targetLook.current.set(...desired.target);
    camera.position.lerp(targetPos.current, 0.04);
    camera.lookAt(targetLook.current);
  });
  return null;
}

