// idleAnalytics.ts
type Event = { name: string; payload: Record<string, unknown> };
const queue: Event[] = [];
let flushing = false;
function flush() {
  while (queue.length > 0) {
    const e = queue.shift()!;
    fetch('/api/track', { method: 'POST', body: JSON.stringify(e), keepalive: true }).catch(() => {});
  }
  flushing = false;
}
export function trackEvent(name: string, payload: Record<string, unknown> = {}) {
  queue.push({ name, payload });
  if (flushing) return;
  flushing = true;
  if ('requestIdleCallback' in window) (window as any).requestIdleCallback(flush, { timeout: 2000 });
  else setTimeout(flush, 100);
}

