// TwoPaneExplorer.tsx
import { useState, useRef, useEffect } from 'react';
export function TwoPaneExplorer({ leftPane, rightPane, persistKey, defaultLeftWidth = 320, minLeft = 240, maxLeft = 600 }: { leftPane: React.ReactNode; rightPane: React.ReactNode; persistKey: string; defaultLeftWidth?: number; minLeft?: number; maxLeft?: number }) {
  const [leftWidth, setLeftWidth] = useState<number>(() => { try { return parseInt(localStorage.getItem(`${persistKey}-w`) ?? String(defaultLeftWidth), 10); } catch { return defaultLeftWidth; } });
  useEffect(() => { try { localStorage.setItem(`${persistKey}-w`, String(leftWidth)); } catch {} }, [leftWidth, persistKey]);
  const onMouseDown = (e: React.MouseEvent) => {
    const startX = e.clientX; const startW = leftWidth;
    const onMove = (ev: MouseEvent) => setLeftWidth(Math.max(minLeft, Math.min(maxLeft, startW + ev.clientX - startX)));
    const onUp = () => { document.removeEventListener('mousemove', onMove); document.removeEventListener('mouseup', onUp); };
    document.addEventListener('mousemove', onMove); document.addEventListener('mouseup', onUp);
  };
  return (
    <div className="flex h-screen">
      <div style={{ width: leftWidth }} className="overflow-y-auto border-r border-[oklch(0.92_0.005_250)]">{leftPane}</div>
      <div onMouseDown={onMouseDown} role="separator" aria-orientation="vertical" className="w-1.5 cursor-col-resize hover:bg-[oklch(0.55_0.18_250)]" />
      <div className="flex-1 overflow-y-auto">{rightPane}</div>
    </div>
  );
}

