import { useEffect } from 'react';
export function BulkActionBar({ selectedCount, actions, onClearSelection }: { selectedCount: number; actions: ReadonlyArray<{ id: string; label: string; onClick: () => void; shortcut?: string }>; onClearSelection: () => void }) {
  useEffect(() => {
