// NumberStepper.tsx
import { useState, useRef } from 'react';
export function NumberStepper({ value, onChange, step = 1, min, max }: { value: number; onChange: (v: number) => void; step?: number; min?: number; max?: number }) {
  const intervalRef = useRef<number | null>(null);
  const startHold = (delta: number) => {
    onChange(clamp(value + delta));
    let elapsed = 0;
    intervalRef.current = window.setInterval(() => {
      elapsed += 200;
      onChange(clamp(value + delta));
      if (elapsed > 1000) { if (intervalRef.current) { window.clearInterval(intervalRef.current); intervalRef.current = window.setInterval(() => onChange(clamp(value + delta)), 20); } }
      else if (elapsed > 500 && intervalRef.current) { window.clearInterval(intervalRef.current); intervalRef.current = window.setInterval(() => onChange(clamp(value + delta)), 50); }
    }, 200);
  };
  const stopHold = () => { if (intervalRef.current) window.clearInterval(intervalRef.current); intervalRef.current = null; };
  const clamp = (v: number) => { if (min != null) v = Math.max(min, v); if (max != null) v = Math.min(max, v); return v; };
  return (
    <div className="inline-flex items-center border border-[oklch(0.85_0.005_250)] rounded">
      <button type="button" onPointerDown={() => startHold(-step)} onPointerUp={stopHold} onPointerLeave={stopHold} className="w-8 h-8 hover:bg-[oklch(0.95_0.005_250)]" aria-label="Decrease">\u2212</button>
      <input type="number" value={value} onChange={(e) => onChange(clamp(Number(e.target.value)))} className="w-16 text-center font-mono tabular-nums text-[14px] outline-none" />
      <button type="button" onPointerDown={() => startHold(step)} onPointerUp={stopHold} onPointerLeave={stopHold} className="w-8 h-8 hover:bg-[oklch(0.95_0.005_250)]" aria-label="Increase">+</button>
    </div>
  );
}

// BubbleChart.tsx
import { useState } from 'react';
export interface Bubble { id: string; x: number; y: number; size: number; color: string; label: string; }
export function BubbleChart({ bubbles, width = 600, height = 400 }: { bubbles: ReadonlyArray<Bubble>; width?: number; height?: number }) {
  const [hoverId, setHoverId] = useState<string | null>(null);
  const xMin = Math.min(...bubbles.map(b => b.x)), xMax = Math.max(...bubbles.map(b => b.x));
  const yMin = Math.min(...bubbles.map(b => b.y)), yMax = Math.max(...bubbles.map(b => b.y));
  const sMax = Math.max(...bubbles.map(b => b.size));
  const xScale = (v: number) => 40 + ((v - xMin) / (xMax - xMin)) * (width - 80);
  const yScale = (v: number) => height - 40 - ((v - yMin) / (yMax - yMin)) * (height - 80);
  const rScale = (s: number) => Math.sqrt((s / sMax) * 60 * 60 * Math.PI) / Math.PI * 2;
  return (
    <div className="relative">
      <svg width={width} height={height}>
        {bubbles.map(b => <circle key={b.id} cx={xScale(b.x)} cy={yScale(b.y)} r={rScale(b.size)} fill={b.color} fillOpacity={0.6} stroke={b.color} onMouseEnter={() => setHoverId(b.id)} onMouseLeave={() => setHoverId(null)} className="cursor-pointer" />)}
      </svg>
      {hoverId && (() => { const b = bubbles.find(x => x.id === hoverId)!; return <div className="absolute bg-[oklch(0.18_0.005_250)] text-white text-[12px] px-2 py-1 rounded" style={{ left: xScale(b.x), top: yScale(b.y) - 30 }}>{b.label}</div>; })()}
    </div>
  );
}

